import json
import os

# Read the first few records from both databases to verify they are different
print("=== First 5 repos from metadata database (languages) ===")
meta_file = '/root/tool_results/var_functions.query_db:60.json'
if os.path.exists(meta_file):
    with open(meta_file, 'r') as f:
        meta_repos = json.load(f)
    for i, repo in enumerate(meta_repos[:5]):
        print(f"  {i+1}. {repo['repo_name']}")
else:
    print("File not found")

print("\n=== First 5 repos from artifacts database (README files) ===")
artifacts_file = '/root/tool_results/var_functions.query_db:36.json'
if os.path.exists(artifacts_file):
    with open(artifacts_file, 'r') as f:
        artifact_repos = json.load(f)
    for i, repo in enumerate(artifact_repos[:5]):
        print(f"  {i+1}. {repo['sample_repo_name']}")
else:
    print("File not found")

# Check if there are ANY overlaps
if os.path.exists(meta_file) and os.path.exists(artifacts_file):
    meta_set = {repo['repo_name'] for repo in meta_repos}
    artifact_set = {repo['sample_repo_name'] for repo in artifact_repos}

    overlaps = meta_set.intersection(artifact_set)
    print(f"\n=== Overlaps between databases: {len(overlaps)} ===")
    if overlaps:
        for repo in list(overlaps)[:10]:
            print(f"  {repo}")
    else:
        print("  No overlaps found - the databases contain different repositories!")
        print(f"  Metadata database has {len(meta_set)} unique repositories")
        print(f"  Artifacts database has {len(artifact_set)} unique repositories")

result = {
    'meta_repos_count': len(meta_repos) if 'meta_repos' in locals() else 0,
    'artifact_repos_count': len(artifact_repos) if 'artifact_repos' in locals() else 0,
    'overlaps': len(overlaps) if 'overlaps' in locals() else 0
}

print('__RESULT__:')
print(json.dumps(result))

